<?php
 namespace WPAICG\AutoGPT\Cron\Queuer; use WP_Query; if (!defined('ABSPATH')) { exit; } require_once __DIR__ . '/helpers/build-index-item-config.php'; require_once __DIR__ . '/helpers/insert-item-into-queue.php'; require_once __DIR__ . '/helpers/update-task-flag.php'; function maybe_queue_initial_indexing_content_logic(int $task_id, array $task_config, bool $force_all = false): void { global $wpdb; $queue_table_name = $wpdb->prefix . 'aipkit_automated_task_queue'; $tasks_table_name = $wpdb->prefix . 'aipkit_automated_tasks'; $transient_key = 'aipkit_initial_queue_page_' . $task_id; $completed_transient_key = 'aipkit_initial_queue_done_' . $task_id; if ($force_all) { delete_transient($completed_transient_key); delete_transient($transient_key); } $is_already_completed = get_transient($completed_transient_key); $initial_indexing_flag_set = isset($task_config['index_existing_now_flag']) && $task_config['index_existing_now_flag'] === '1'; if (!$force_all && ($is_already_completed || !$initial_indexing_flag_set)) { return; } $page_to_process = get_transient($transient_key); if ($page_to_process === false) { $page_to_process = 1; } $batch_size = 200; $args = [ 'post_type' => $task_config['post_types'] ?? ['post'], 'post_status' => 'publish', 'posts_per_page' => $batch_size, 'paged' => $page_to_process, 'fields' => 'ids', 'orderby' => 'ID', 'order' => 'ASC', ]; $query = new WP_Query($args); $queued_count = 0; if ($query->have_posts()) { $item_config = Helpers\build_index_item_config_logic($task_config); foreach ($query->posts as $post_id) { $inserted = Helpers\insert_item_into_queue_logic($wpdb, $queue_table_name, $task_id, $post_id, 'content_indexing', $item_config); if ($inserted) { $queued_count++; } } } if ($page_to_process < $query->max_num_pages) { set_transient($transient_key, $page_to_process + 1, DAY_IN_SECONDS * 7); } else { delete_transient($transient_key); set_transient($completed_transient_key, 'yes', MONTH_IN_SECONDS); if (!$force_all) { Helpers\update_task_flag_logic($wpdb, $tasks_table_name, $task_id, $task_config); } } } 